SLIDE_CREDITS_PHOTOGRAPH:
C4F46F_SlideCreditsPhotograph = SLIDE_CREDITS_PHOTOGRAPH
    ; Move the active photograph along the vector encoded in its E1:2F8A record.
    ; The inner loop updates BG3 scroll words and drains one queued credits DMA
    ; record per frame so text rows keep streaming during the slide.
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFDC
    tcd
    pla
    sta $22
    lda.w #PhotographerCfgTableLo
    sta $06
    lda.w #PhotographerCfgTableBank
    sta $08
    lda $22
    ldy.w #PhotographerCfgRecordStride
    jsl Multiply16By8_ViaHardwareRegisters
    clc
    adc $06
    sta $06
    sta $1E
    lda $08
    sta $20
    ; The photograph record contributes only the slide angle and frame count;
    ; the projection/division helpers own the math details.
    ldx.w #CreditsPhotoSlideFractionUnit
    sep #$20
    ldy.w #PhotographerCfgSlideAngleOffset
    lda [$06],Y
    rep #$20
    and.w #$00FF
    ldy.w #CreditsPhotoSlideProjectionMagnitude
    jsl Multiply16By16_ViaHardwareRegisters
    jsl ProjectMagnitudeByDirectionAngle
    lda $06
    sta $0A
    lda $08
    sta $0C
    lda $0A
    sta $06
    lda $0C
    sta $08
    lda $06
    sta $0E
    lda $08
    sta $10
    lda $1E
    sta $06
    lda $20
    sta $08
    sep #$20
    ldy.w #PhotographerCfgSlideFrameCountOffset
    lda [$06],Y
    rep #$20
    and.w #$00FF
    xba
    and.w #$FF00
    ldy.w #CreditsPhotoSlideFractionUnit
    jsl Divide16By16_ViaHardwareRegisters
    sta $22
    lda $10
    sta $1C
    lda $0E
    sta $1A
    lda Bg3HScrollLow
    sta $18
    lda Bg3VScrollLow
    sta $16
    lda.w #$0000
    sta $04
    sta $02
    tay
    sty $14
    bra C4F54E_SlideCreditsPhotograph_LF54E
C4F50A_SlideCreditsPhotograph_LF50A:
    lda $02
    clc
    adc $1C
